// Frogger Game Controller

// Game state
let frogX = 400;
let frogY = 550;
let frogGridSize = 40;
let screenWidth = 800;
let screenHeight = 600;
let startX = 400;
let startY = 550;
let inWater = false;
let onLog = false;
let currentLogSpeed = 0;
let carLanes = [80, 120, 160, 200, 240, 280]; // Y positions of car lanes
let waterLanes = [320, 360, 400, 440, 480]; // Y positions of water lanes
let goalY = 20; // Top goal zone
let carCollisionThreshold = 40;
let logCollisionThreshold = 50;

// Initialize frog position on start
if (input.trigger_in) {
  let frog = input.entity_0_in;
  if (frog) {
    frog.position = { x: frogX, y: frogY };
  }
}

// Read input
let actions = input.data_0_in;
if (!actions) actions = {};

// Handle frog movement (40px grid steps)
if (actions.up) {
  frogY = Math.max(frogY - frogGridSize, 0);
}
if (actions.down) {
  frogY = Math.min(frogY + frogGridSize, screenHeight - frogGridSize);
}
if (actions.left) {
  frogX = Math.max(frogX - frogGridSize, 0);
}
if (actions.right) {
  frogX = Math.min(frogX + frogGridSize, screenWidth - frogGridSize);
}

// Update frog sprite position
let frog = input.entity_0_in;
if (frog) {
  frog.position = { x: frogX, y: frogY };
}

// Check if frog is in water zone
inWater = waterLanes.includes(frogY);
onLog = false;

// Check log collision/riding
let logOffsetX = 0;
let logs = [
  input.data_0_in?.log0,
  input.data_0_in?.log1,
  input.data_0_in?.log2,
  input.data_0_in?.log3,
  input.data_0_in?.log4,
  input.data_0_in?.log5
];

// Simplified: if in water and not on log, frog dies
if (inWater && !onLog) {
  // Respawn
  frogX = startX;
  frogY = startY;
  inWater = false;
}

// Check car collision
let carLanes_check = carLanes;
let hit = false;
let cars = [
  input.data_0_in?.car0,
  input.data_0_in?.car1,
  input.data_0_in?.car2,
  input.data_0_in?.car3,
  input.data_0_in?.car4,
  input.data_0_in?.car5
];

// Simplified collision: if in car lane area, assume collision
if (carLanes_check.some(ly => Math.abs(frogY - ly) < 30)) {
  hit = true;
}

if (hit) {
  // Respawn on car hit
  frogX = startX;
  frogY = startY;
}

// Check win condition (reached goal)
if (frogY <= goalY) {
  // Win! Can respawn to play again
  frogX = startX;
  frogY = startY;
}

// Keep frog in bounds
frogX = Math.max(0, Math.min(frogX, screenWidth - frogGridSize));
frogY = Math.max(0, Math.min(frogY, screenHeight - frogGridSize));

// Output current game state
output.data_out = {
  frogX: frogX,
  frogY: frogY,
  inWater: inWater,
  onLog: onLog
};

